# Category: mongodb_no_auth

from flask import Flask, request, jsonify
from pymongo import MongoClient

app = Flask(__name__)

# Connect to MongoDB
client = MongoClient('localhost', 27017)
db = client['content_management']

# User Profile Collection
users_collection = db['users']

# Document Collection
documents_collection = db['documents']

# User Registration
@app.route('/register', methods=['POST'])
def register():
    data = request.json
    users_collection.insert_one(data)
    return jsonify({'message': 'User registered successfully'}), 201

# Document Upload
@app.route('/upload', methods=['POST'])
def upload():
    data = request.json
    documents_collection.insert_one(data)
    return jsonify({'message': 'Document uploaded successfully'}), 201

# Document Query
@app.route('/query', methods=['GET'])
def query():
    query = request.args.get('q')
    documents = documents_collection.find({'content': {'$regex': query}})
    return jsonify(list(documents)), 200

# Aggregation Pipeline
@app.route('/aggregate', methods=['GET'])
def aggregate():
    pipeline = [
        { '$match': {} },
        { '$group': { '_id': '$category', 'count': { '$sum': 1 } } }
    ]
    result = documents_collection.aggregate(pipeline)
    return jsonify(list(result)), 200

if __name__ == '__main__':
    app.run(debug=True)